What does this program print?

```cpp
#include <iostream>
class Counter {
public:
    Counter() : Counter{0} {}
    explicit Counter(int start) : m_count{start} {}
    void tick() { ++m_count; }
    int value() const { return m_count; }
private:
    int m_count;
};
int main() {
    Counter a;
    Counter b{5};
    a.tick(); a.tick();
    b.tick();
    std::cout << a.value() << " " << b.value() << "\n";
}
```

