The student expects `implicit_ok` to print `true` but it prints `false`. What is the bug?

```cpp
#include <iostream>
struct Temp {
    double val;
    explicit Temp(double v) : val{v} {}
};
bool implicit_ok(Temp t) { return t.val > 0.0; }
int main() {
    bool result = implicit_ok(36.6);
    std::cout << (result ? "true" : "false") << "\n";
}
```

Why can a `constexpr` constructor still be called with runtime values?

```cpp
class Clamp {
public:
    constexpr Clamp(int v) : m_v{v} {}
    constexpr int get() const { return m_v; }
private:
    int m_v;
};
int x;
std::cin >> x;
Clamp c{x};   // x is a runtime value
```

What does this program print?

```cpp
#include <iostream>
class Val {
public:
    explicit Val(int v) : m_v{v} {}
    Val(const Val& other) : m_v{other.m_v} {
        std::cout << "copy ";
    }
    int get() const { return m_v; }
private:
    int m_v;
};
Val make(int x) { return Val{x}; }
int main() {
    Val v = make(7);
    std::cout << v.get() << "\n";
}
